    async establishServiceConnection(service) {
        const credentials = this.getRequiredCredentials(service.type);
        
        if (!credentials.clientId || !credentials.clientSecret) {
            console.warn(`  ⚠️ Missing credentials for ${service.name}`);
            return null;
        }
        
        try {
            // Simulate OAuth2 flow for Google APIs
            const authResult = await this.performGoogleAuth(service.type, credentials);
            
            if (authResult.success) {
                return {
                    service: service.type,
                    name: service.name,
                    endpoint: service.endpoint,
                    accessToken: authResult.accessToken,
                    refreshToken: authResult.refreshToken,
                    expiresAt: authResult.expiresAt,
                    credentials: credentials,
                    connectedAt: new Date()
                };
            }
        } catch (error) {
            console.error(`  ❌ Authentication failed for ${service.name}:`, error.message);
        }
        
        return null;
    }

    getRequiredCredentials(serviceType) {
        const baseCredentials = {
            clientId: this.googleCredentials.GOOGLE_CLIENT_ID,
            clientSecret: this.googleCredentials.GOOGLE_CLIENT_SECRET
        };
        
        switch (serviceType) {
            case 'gmc':
                return {
                    ...baseCredentials,
                    merchantId: this.googleCredentials.GMC_MERCHANT_ID
                };
                
            case 'ads':
                return {
                    ...baseCredentials,
                    developerToken: this.googleCredentials.GOOGLE_ADS_DEVELOPER_TOKEN,
                    clientId: this.googleCredentials.GOOGLE_ADS_CLIENT_ID,
                    clientSecret: this.googleCredentials.GOOGLE_ADS_CLIENT_SECRET,
                    refreshToken: this.googleCredentials.GOOGLE_ADS_REFRESH_TOKEN,
                    customerId: this.googleCredentials.GOOGLE_ADS_CUSTOMER_ID
                };
                
            case 'youtube':
                return {
                    ...baseCredentials,
                    apiKey: this.googleCredentials.YOUTUBE_API_KEY,
                    channelId: this.googleCredentials.YOUTUBE_CHANNEL_ID,
                    userId: this.googleCredentials.YOUTUBE_USER_ID
                };
                
            default:
                return baseCredentials;
        }
    }

